/**
 * Audit logging service — records every notification dispatched.
 *
 * Provides an append-only log of all notifications routed through the system,
 * including channel, priority, recipient, and timestamp information.
 */

import type { NotificationPriority } from './priority-router.js';

export interface AuditEntry {
  id: string;
  channel: 'sms' | 'email' | 'webhook';
  priority: NotificationPriority;
  recipient: string;
  subject: string;
  timestamp: Date;
}

let nextId = 1;

function generateAuditId(): string {
  return `audit-${String(nextId++).padStart(4, '0')}`;
}

export function resetAuditIdCounter(): void {
  nextId = 1;
}

export class AuditService {
  private entries: AuditEntry[] = [];

  record(params: {
    channel: 'sms' | 'email' | 'webhook';
    priority: NotificationPriority;
    recipient: string;
    subject: string;
  }): AuditEntry {
    const entry: AuditEntry = {
      id: generateAuditId(),
      channel: params.channel,
      priority: params.priority,
      recipient: params.recipient,
      subject: params.subject,
      timestamp: new Date(),
    };
    this.entries.push(entry);
    return entry;
  }

  getEntries(): AuditEntry[] {
    return [...this.entries];
  }

  getEntriesForRecipient(recipient: string): AuditEntry[] {
    return this.entries.filter((e) => e.recipient === recipient);
  }

  getEntriesByChannel(channel: 'sms' | 'email' | 'webhook'): AuditEntry[] {
    return this.entries.filter((e) => e.channel === channel);
  }

  getEntryCount(): number {
    return this.entries.length;
  }

  clear(): void {
    this.entries = [];
  }
}

/**
 * Notification preferences service — manages per-user channel preferences.
 *
 * When a user has a channel preference set, it overrides the default
 * priority-based routing. For example, a user can request all notifications
 * be delivered via SMS regardless of priority level.
 */

export type ChannelPreference = 'sms' | 'email' | 'webhook';

export class NotificationPreferencesService {
  private preferences: Map<string, ChannelPreference> = new Map();

  setPreference(userId: string, channel: ChannelPreference): void {
    this.preferences.set(userId, channel);
  }

  getPreference(userId: string): ChannelPreference | undefined {
    return this.preferences.get(userId);
  }

  removePreference(userId: string): boolean {
    return this.preferences.delete(userId);
  }

  hasPreference(userId: string): boolean {
    return this.preferences.has(userId);
  }

  getAllPreferences(): Map<string, ChannelPreference> {
    return new Map(this.preferences);
  }

  clear(): void {
    this.preferences.clear();
  }
}

/**
 * Priority-based notification router.
 *
 * Routes notifications to the appropriate channel based on priority:
 * - urgent → SMS channel
 * - normal → email channel
 * - low → webhook channel
 *
 * Per-user channel preferences (via NotificationPreferencesService) override
 * the default priority-based routing when set.
 *
 * All dispatched notifications are recorded via AuditService when provided.
 */

import type { NotificationService } from './notification.service.js';
import type { SmsNotificationService } from './sms-notification.service.js';
import type { WebhookNotificationService } from './webhook-notification.service.js';
import type { AuditService } from './audit.service.js';
import type { NotificationPreferencesService } from './notification-preferences.service.js';
import { Logger } from '../utils/logger.js';

export type NotificationPriority = 'urgent' | 'normal' | 'low';

export interface PriorityNotification {
  priority: NotificationPriority;
  recipient: string;
  subject: string;
  body: string;
}

export interface RoutingResult {
  channel: 'sms' | 'email' | 'webhook';
  priority: NotificationPriority;
  recipient: string;
  overridden: boolean;
}

export class PriorityRouter {
  private logger = new Logger('PriorityRouter');

  constructor(
    private smsService: SmsNotificationService,
    private emailService: NotificationService,
    private webhookService: WebhookNotificationService,
    private auditService?: AuditService,
    private preferencesService?: NotificationPreferencesService,
  ) {}

  route(notification: PriorityNotification): RoutingResult {
    const { priority } = notification;

    // Check for per-user channel preference override
    let channel = this.getDefaultChannel(priority);
    let overridden = false;

    if (this.preferencesService) {
      const preference = this.preferencesService.getPreference(notification.recipient);
      if (preference) {
        this.logger.info(
          `User ${notification.recipient} has channel preference: ${preference} (overriding ${channel})`,
        );
        channel = preference;
        overridden = true;
      }
    }

    this.dispatch(channel, notification);

    const result: RoutingResult = { channel, priority, recipient: notification.recipient, overridden };

    // Record in audit log
    if (this.auditService) {
      this.auditService.record({
        channel,
        priority,
        recipient: notification.recipient,
        subject: notification.subject,
      });
    }

    return result;
  }

  private getDefaultChannel(priority: NotificationPriority): 'sms' | 'email' | 'webhook' {
    switch (priority) {
      case 'urgent':
        return 'sms';
      case 'normal':
        return 'email';
      case 'low':
        return 'webhook';
    }
  }

  private dispatch(
    channel: 'sms' | 'email' | 'webhook',
    notification: PriorityNotification,
  ): void {
    switch (channel) {
      case 'sms':
        this.logger.info(`Routing notification to SMS: ${notification.subject}`);
        this.smsService.sendDirect({
          phoneNumber: notification.recipient,
          message: `[${notification.priority.toUpperCase()}] ${notification.subject}: ${notification.body}`,
        });
        break;

      case 'email':
        this.logger.info(`Routing notification to email: ${notification.subject}`);
        this.emailService.sendDirect({
          recipient: notification.recipient,
          subject: notification.subject,
          body: notification.body,
        });
        break;

      case 'webhook':
        this.logger.info(`Routing notification to webhook: ${notification.subject}`);
        this.webhookService.sendDirect({
          eventType: 'notification',
          payload: {
            recipient: notification.recipient,
            subject: notification.subject,
            body: notification.body,
            priority: notification.priority,
          },
        });
        break;
    }
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { AuditService, resetAuditIdCounter } from '../../src/services/audit.service.js';

describe('AuditService', () => {
  let service: AuditService;

  beforeEach(() => {
    service = new AuditService();
    resetAuditIdCounter();
  });

  it('should record an audit entry', () => {
    const entry = service.record({
      channel: 'sms',
      priority: 'urgent',
      recipient: 'user-1',
      subject: 'Test notification',
    });

    expect(entry.id).toBe('audit-0001');
    expect(entry.channel).toBe('sms');
    expect(entry.priority).toBe('urgent');
    expect(entry.recipient).toBe('user-1');
    expect(entry.subject).toBe('Test notification');
    expect(entry.timestamp).toBeInstanceOf(Date);
  });

  it('should generate sequential IDs', () => {
    service.record({ channel: 'sms', priority: 'urgent', recipient: 'u1', subject: 's1' });
    service.record({ channel: 'email', priority: 'normal', recipient: 'u2', subject: 's2' });
    service.record({ channel: 'webhook', priority: 'low', recipient: 'u3', subject: 's3' });

    const entries = service.getEntries();
    expect(entries[0]?.id).toBe('audit-0001');
    expect(entries[1]?.id).toBe('audit-0002');
    expect(entries[2]?.id).toBe('audit-0003');
  });

  it('should filter entries by recipient', () => {
    service.record({ channel: 'sms', priority: 'urgent', recipient: 'alice', subject: 's1' });
    service.record({ channel: 'email', priority: 'normal', recipient: 'bob', subject: 's2' });
    service.record({ channel: 'webhook', priority: 'low', recipient: 'alice', subject: 's3' });

    expect(service.getEntriesForRecipient('alice')).toHaveLength(2);
    expect(service.getEntriesForRecipient('bob')).toHaveLength(1);
    expect(service.getEntriesForRecipient('charlie')).toHaveLength(0);
  });

  it('should filter entries by channel', () => {
    service.record({ channel: 'sms', priority: 'urgent', recipient: 'u1', subject: 's1' });
    service.record({ channel: 'email', priority: 'normal', recipient: 'u2', subject: 's2' });
    service.record({ channel: 'sms', priority: 'urgent', recipient: 'u3', subject: 's3' });

    expect(service.getEntriesByChannel('sms')).toHaveLength(2);
    expect(service.getEntriesByChannel('email')).toHaveLength(1);
    expect(service.getEntriesByChannel('webhook')).toHaveLength(0);
  });

  it('should count entries', () => {
    expect(service.getEntryCount()).toBe(0);
    service.record({ channel: 'sms', priority: 'urgent', recipient: 'u1', subject: 's1' });
    expect(service.getEntryCount()).toBe(1);
  });

  it('should clear entries', () => {
    service.record({ channel: 'sms', priority: 'urgent', recipient: 'u1', subject: 's1' });
    service.clear();
    expect(service.getEntryCount()).toBe(0);
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { NotificationPreferencesService } from '../../src/services/notification-preferences.service.js';

describe('NotificationPreferencesService', () => {
  let service: NotificationPreferencesService;

  beforeEach(() => {
    service = new NotificationPreferencesService();
  });

  it('should set and get a preference', () => {
    service.setPreference('user-1', 'sms');
    expect(service.getPreference('user-1')).toBe('sms');
  });

  it('should return undefined for unknown user', () => {
    expect(service.getPreference('unknown')).toBeUndefined();
  });

  it('should override existing preference', () => {
    service.setPreference('user-1', 'sms');
    service.setPreference('user-1', 'email');
    expect(service.getPreference('user-1')).toBe('email');
  });

  it('should remove a preference', () => {
    service.setPreference('user-1', 'sms');
    expect(service.removePreference('user-1')).toBe(true);
    expect(service.getPreference('user-1')).toBeUndefined();
  });

  it('should return false when removing non-existent preference', () => {
    expect(service.removePreference('unknown')).toBe(false);
  });

  it('should check if preference exists', () => {
    service.setPreference('user-1', 'webhook');
    expect(service.hasPreference('user-1')).toBe(true);
    expect(service.hasPreference('user-2')).toBe(false);
  });

  it('should return all preferences', () => {
    service.setPreference('user-1', 'sms');
    service.setPreference('user-2', 'email');

    const all = service.getAllPreferences();
    expect(all.size).toBe(2);
    expect(all.get('user-1')).toBe('sms');
    expect(all.get('user-2')).toBe('email');
  });

  it('should clear all preferences', () => {
    service.setPreference('user-1', 'sms');
    service.setPreference('user-2', 'email');
    service.clear();

    expect(service.hasPreference('user-1')).toBe(false);
    expect(service.getAllPreferences().size).toBe(0);
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import { SmsNotificationService, resetSmsIdCounter } from '../../src/services/sms-notification.service.js';
import { WebhookNotificationService, resetWebhookIdCounter } from '../../src/services/webhook-notification.service.js';
import { PriorityRouter } from '../../src/services/priority-router.js';
import { AuditService, resetAuditIdCounter } from '../../src/services/audit.service.js';
import { NotificationPreferencesService } from '../../src/services/notification-preferences.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';

describe('Notification Flow Integration', () => {
  let eventBus: EventBus;
  let emailService: NotificationService;
  let smsService: SmsNotificationService;
  let webhookService: WebhookNotificationService;
  let auditService: AuditService;
  let preferencesService: NotificationPreferencesService;
  let router: PriorityRouter;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    resetNotificationIdCounter();
    resetSmsIdCounter();
    resetWebhookIdCounter();
    resetAuditIdCounter();

    emailService = new NotificationService(eventBus);
    smsService = new SmsNotificationService(eventBus);
    webhookService = new WebhookNotificationService(eventBus);
    auditService = new AuditService();
    preferencesService = new NotificationPreferencesService();

    webhookService.registerWebhookUrl('https://hooks.example.com/notifications');

    router = new PriorityRouter(smsService, emailService, webhookService, auditService, preferencesService);
  });

  describe('priority routing → channel selection → audit log', () => {
    it('should route urgent notifications to SMS and create audit entry', () => {
      const result = router.route({
        priority: 'urgent',
        recipient: '+15551234567',
        subject: 'Server Down',
        body: 'Production server is unresponsive',
      });

      expect(result.channel).toBe('sms');
      expect(result.priority).toBe('urgent');
      expect(result.overridden).toBe(false);

      // Verify SMS was sent
      const messages = smsService.getMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.phoneNumber).toBe('+15551234567');
      expect(messages[0]?.message).toContain('[URGENT]');
      expect(messages[0]?.message).toContain('Server Down');

      // Verify audit entry was created
      const auditEntries = auditService.getEntries();
      expect(auditEntries).toHaveLength(1);
      expect(auditEntries[0]?.channel).toBe('sms');
      expect(auditEntries[0]?.priority).toBe('urgent');
      expect(auditEntries[0]?.recipient).toBe('+15551234567');
      expect(auditEntries[0]?.subject).toBe('Server Down');

      // Verify email was NOT sent via priority router
      expect(emailService.getNotificationCount()).toBe(0);
    });

    it('should route normal notifications to email and create audit entry', () => {
      const result = router.route({
        priority: 'normal',
        recipient: 'alice@example.com',
        subject: 'Order Shipped',
        body: 'Your order has been shipped',
      });

      expect(result.channel).toBe('email');
      expect(result.priority).toBe('normal');
      expect(result.overridden).toBe(false);

      // Verify email was sent
      const notifications = emailService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.recipient).toBe('alice@example.com');
      expect(notifications[0]?.subject).toBe('Order Shipped');

      // Verify audit entry
      const auditEntries = auditService.getEntries();
      expect(auditEntries).toHaveLength(1);
      expect(auditEntries[0]?.channel).toBe('email');

      // Verify SMS was NOT sent
      expect(smsService.getMessageCount()).toBe(0);
    });

    it('should route low-priority notifications to webhook and create audit entry', () => {
      const result = router.route({
        priority: 'low',
        recipient: 'system-monitor',
        subject: 'Daily Report',
        body: 'All systems nominal',
      });

      expect(result.channel).toBe('webhook');
      expect(result.priority).toBe('low');
      expect(result.overridden).toBe(false);

      // Verify webhook was delivered
      const deliveries = webhookService.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.eventType).toBe('notification');

      // Verify audit entry
      const auditEntries = auditService.getEntries();
      expect(auditEntries).toHaveLength(1);
      expect(auditEntries[0]?.channel).toBe('webhook');
      expect(auditEntries[0]?.subject).toBe('Daily Report');
    });
  });

  describe('user preference overrides', () => {
    it('should override urgent→SMS to email when user prefers email', () => {
      preferencesService.setPreference('alice@example.com', 'email');

      const result = router.route({
        priority: 'urgent',
        recipient: 'alice@example.com',
        subject: 'Critical Alert',
        body: 'Something urgent happened',
      });

      expect(result.channel).toBe('email');
      expect(result.overridden).toBe(true);

      // Verify email was sent (not SMS)
      expect(emailService.getNotificationCount()).toBe(1);
      expect(smsService.getMessageCount()).toBe(0);

      // Audit should record the overridden channel
      const auditEntries = auditService.getEntries();
      expect(auditEntries[0]?.channel).toBe('email');
      expect(auditEntries[0]?.priority).toBe('urgent');
    });

    it('should override low→webhook to SMS when user prefers SMS', () => {
      preferencesService.setPreference('bob', 'sms');

      const result = router.route({
        priority: 'low',
        recipient: 'bob',
        subject: 'Info Update',
        body: 'Minor update available',
      });

      expect(result.channel).toBe('sms');
      expect(result.overridden).toBe(true);

      expect(smsService.getMessageCount()).toBe(1);
      expect(webhookService.getDeliveryCount()).toBe(0);

      const auditEntries = auditService.getEntries();
      expect(auditEntries[0]?.channel).toBe('sms');
    });

    it('should use default routing when user has no preference', () => {
      // No preference set for charlie
      const result = router.route({
        priority: 'normal',
        recipient: 'charlie@example.com',
        subject: 'Hello',
        body: 'Just a normal notification',
      });

      expect(result.channel).toBe('email');
      expect(result.overridden).toBe(false);
    });
  });

  describe('multiple notifications with audit trail', () => {
    it('should maintain complete audit trail across multiple dispatches', () => {
      router.route({ priority: 'urgent', recipient: 'u1', subject: 'Alert 1', body: 'b1' });
      router.route({ priority: 'normal', recipient: 'u2', subject: 'Update 1', body: 'b2' });
      router.route({ priority: 'low', recipient: 'u3', subject: 'Info 1', body: 'b3' });

      const entries = auditService.getEntries();
      expect(entries).toHaveLength(3);

      expect(entries[0]?.channel).toBe('sms');
      expect(entries[0]?.id).toBe('audit-0001');
      expect(entries[1]?.channel).toBe('email');
      expect(entries[1]?.id).toBe('audit-0002');
      expect(entries[2]?.channel).toBe('webhook');
      expect(entries[2]?.id).toBe('audit-0003');
    });

    it('should correctly audit mixed default and overridden routing', () => {
      preferencesService.setPreference('vip-user', 'sms');

      router.route({ priority: 'low', recipient: 'vip-user', subject: 'VIP Notice', body: 'b1' });
      router.route({ priority: 'low', recipient: 'regular-user', subject: 'Regular Notice', body: 'b2' });

      const entries = auditService.getEntries();
      expect(entries).toHaveLength(2);

      // VIP user: overridden to SMS
      expect(entries[0]?.recipient).toBe('vip-user');
      expect(entries[0]?.channel).toBe('sms');

      // Regular user: default webhook
      expect(entries[1]?.recipient).toBe('regular-user');
      expect(entries[1]?.channel).toBe('webhook');
    });
  });

  describe('backward compatibility', () => {
    it('should work without audit and preferences services', () => {
      const basicRouter = new PriorityRouter(smsService, emailService, webhookService);

      const result = basicRouter.route({
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'Test',
        body: 'Test body',
      });

      expect(result.channel).toBe('sms');
      expect(result.overridden).toBe(false);
      expect(smsService.getMessageCount()).toBe(1);
    });
  });
});

