+import { describe, it, expect, beforeEach } from 'vitest';
+import { EventBus } from '../../src/events/event-bus.js';
+import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
+import { SmsNotificationService, resetSmsIdCounter } from '../../src/services/sms-notification.service.js';
+import { WebhookNotificationService, resetWebhookIdCounter } from '../../src/services/webhook-notification.service.js';
+import { PriorityRouter } from '../../src/services/priority-router.js';
+import { AuditService, resetAuditIdCounter } from '../../src/services/audit.service.js';
+import { NotificationPreferencesService } from '../../src/services/notification-preferences.service.js';
+import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
+
+describe('Notification Flow Integration', () => {
+  let eventBus: EventBus;
+  let emailService: NotificationService;
+  let smsService: SmsNotificationService;
+  let webhookService: WebhookNotificationService;
+  let auditService: AuditService;
+  let preferencesService: NotificationPreferencesService;
+  let router: PriorityRouter;
+
+  beforeEach(() => {
+    eventBus = new EventBus();
+    statusChangeCallbacks.clear();
+    resetNotificationIdCounter();
+    resetSmsIdCounter();
+    resetWebhookIdCounter();
+    resetAuditIdCounter();
+
+    emailService = new NotificationService(eventBus);
+    smsService = new SmsNotificationService(eventBus);
+    webhookService = new WebhookNotificationService(eventBus);
+    auditService = new AuditService();
+    preferencesService = new NotificationPreferencesService();
+
+    webhookService.registerWebhookUrl('https://hooks.example.com/notifications');
+
+    router = new PriorityRouter(smsService, emailService, webhookService, auditService, preferencesService);
+  });
+
+  describe('priority routing → channel selection → audit log', () => {
+    it('should route urgent notifications to SMS and create audit entry', () => {
+      const result = router.route({
+        priority: 'urgent',
+        recipient: '+15551234567',
+        subject: 'Server Down',
+        body: 'Production server is unresponsive',
+      });
+
+      expect(result.channel).toBe('sms');
+      expect(result.priority).toBe('urgent');
+      expect(result.overridden).toBe(false);
+
+      // Verify SMS was sent
+      const messages = smsService.getMessages();
+      expect(messages).toHaveLength(1);
+      expect(messages[0]?.phoneNumber).toBe('+15551234567');
+      expect(messages[0]?.message).toContain('[URGENT]');
+      expect(messages[0]?.message).toContain('Server Down');
+
+      // Verify audit entry was created
+      const auditEntries = auditService.getEntries();
+      expect(auditEntries).toHaveLength(1);
+      expect(auditEntries[0]?.channel).toBe('sms');
+      expect(auditEntries[0]?.priority).toBe('urgent');
+      expect(auditEntries[0]?.recipient).toBe('+15551234567');
+      expect(auditEntries[0]?.subject).toBe('Server Down');
+
+      // Verify email was NOT sent via priority router
+      expect(emailService.getNotificationCount()).toBe(0);
+    });
+
+    it('should route normal notifications to email and create audit entry', () => {
+      const result = router.route({
+        priority: 'normal',
+        recipient: 'alice@example.com',
+        subject: 'Order Shipped',
+        body: 'Your order has been shipped',
+      });
+
+      expect(result.channel).toBe('email');
+      expect(result.priority).toBe('normal');
+      expect(result.overridden).toBe(false);
+
+      // Verify email was sent
+      const notifications = emailService.getNotifications();
+      expect(notifications).toHaveLength(1);
+      expect(notifications[0]?.recipient).toBe('alice@example.com');
+      expect(notifications[0]?.subject).toBe('Order Shipped');
+
+      // Verify audit entry
+      const auditEntries = auditService.getEntries();
+      expect(auditEntries).toHaveLength(1);
+      expect(auditEntries[0]?.channel).toBe('email');
+
+      // Verify SMS was NOT sent
+      expect(smsService.getMessageCount()).toBe(0);
+    });
+
+    it('should route low-priority notifications to webhook and create audit entry', () => {
+      const result = router.route({
+        priority: 'low',
+        recipient: 'system-monitor',
+        subject: 'Daily Report',
+        body: 'All systems nominal',
+      });
+
+      expect(result.channel).toBe('webhook');
+      expect(result.priority).toBe('low');
+      expect(result.overridden).toBe(false);
+
+      // Verify webhook was delivered
+      const deliveries = webhookService.getDeliveries();
+      expect(deliveries).toHaveLength(1);
+      expect(deliveries[0]?.eventType).toBe('notification');
+
+      // Verify audit entry
+      const auditEntries = auditService.getEntries();
+      expect(auditEntries).toHaveLength(1);
+      expect(auditEntries[0]?.channel).toBe('webhook');
+      expect(auditEntries[0]?.subject).toBe('Daily Report');
+    });
+  });
+
+  describe('user preference overrides', () => {
+    it('should override urgent→SMS to email when user prefers email', () => {
+      preferencesService.setPreference('alice@example.com', 'email');
+
+      const result = router.route({
+        priority: 'urgent',
+        recipient: 'alice@example.com',
+        subject: 'Critical Alert',
+        body: 'Something urgent happened',
+      });
+
+      expect(result.channel).toBe('email');
+      expect(result.overridden).toBe(true);
+
+      // Verify email was sent (not SMS)
+      expect(emailService.getNotificationCount()).toBe(1);
+      expect(smsService.getMessageCount()).toBe(0);
+
+      // Audit should record the overridden channel
+      const auditEntries = auditService.getEntries();
+      expect(auditEntries[0]?.channel).toBe('email');
+      expect(auditEntries[0]?.priority).toBe('urgent');
+    });
+
+    it('should override low→webhook to SMS when user prefers SMS', () => {
+      preferencesService.setPreference('bob', 'sms');
+
+      const result = router.route({
+        priority: 'low',
+        recipient: 'bob',
+        subject: 'Info Update',
+        body: 'Minor update available',
+      });
+
+      expect(result.channel).toBe('sms');
+      expect(result.overridden).toBe(true);
+
+      expect(smsService.getMessageCount()).toBe(1);
+      expect(webhookService.getDeliveryCount()).toBe(0);
+
+      const auditEntries = auditService.getEntries();
+      expect(auditEntries[0]?.channel).toBe('sms');
+    });
+
+    it('should use default routing when user has no preference', () => {
+      // No preference set for charlie
+      const result = router.route({
+        priority: 'normal',
+        recipient: 'charlie@example.com',
+        subject: 'Hello',
+        body: 'Just a normal notification',
+      });
+
+      expect(result.channel).toBe('email');
+      expect(result.overridden).toBe(false);
+    });
+  });
+
+  describe('multiple notifications with audit trail', () => {
+    it('should maintain complete audit trail across multiple dispatches', () => {
+      router.route({ priority: 'urgent', recipient: 'u1', subject: 'Alert 1', body: 'b1' });
+      router.route({ priority: 'normal', recipient: 'u2', subject: 'Update 1', body: 'b2' });
+      router.route({ priority: 'low', recipient: 'u3', subject: 'Info 1', body: 'b3' });
+
+      const entries = auditService.getEntries();
+      expect(entries).toHaveLength(3);
+
+      expect(entries[0]?.channel).toBe('sms');
+      expect(entries[0]?.id).toBe('audit-0001');
+      expect(entries[1]?.channel).toBe('email');
+      expect(entries[1]?.id).toBe('audit-0002');
+      expect(entries[2]?.channel).toBe('webhook');
+      expect(entries[2]?.id).toBe('audit-0003');
+    });
+
+    it('should correctly audit mixed default and overridden routing', () => {
+      preferencesService.setPreference('vip-user', 'sms');
+
+      router.route({ priority: 'low', recipient: 'vip-user', subject: 'VIP Notice', body: 'b1' });
+      router.route({ priority: 'low', recipient: 'regular-user', subject: 'Regular Notice', body: 'b2' });
+
+      const entries = auditService.getEntries();
+      expect(entries).toHaveLength(2);
+
+      // VIP user: overridden to SMS
+      expect(entries[0]?.recipient).toBe('vip-user');
+      expect(entries[0]?.channel).toBe('sms');
+
+      // Regular user: default webhook
+      expect(entries[1]?.recipient).toBe('regular-user');
+      expect(entries[1]?.channel).toBe('webhook');
+    });
+  });
+
+  describe('backward compatibility', () => {
+    it('should work without audit and preferences services', () => {
+      const basicRouter = new PriorityRouter(smsService, emailService, webhookService);
+
+      const result = basicRouter.route({
+        priority: 'urgent',
+        recipient: 'user-1',
+        subject: 'Test',
+        body: 'Test body',
+      });
+
+      expect(result.channel).toBe('sms');
+      expect(result.overridden).toBe(false);
+      expect(smsService.getMessageCount()).toBe(1);
+    });
+  });
+});

