+import { describe, it, expect, beforeEach } from 'vitest';
+import { AuditService, resetAuditIdCounter } from '../../src/services/audit.service.js';
+
+describe('AuditService', () => {
+  let service: AuditService;
+
+  beforeEach(() => {
+    service = new AuditService();
+    resetAuditIdCounter();
+  });
+
+  it('should record an audit entry', () => {
+    const entry = service.record({
+      channel: 'sms',
+      priority: 'urgent',
+      recipient: 'user-1',
+      subject: 'Test notification',
+    });
+
+    expect(entry.id).toBe('audit-0001');
+    expect(entry.channel).toBe('sms');
+    expect(entry.priority).toBe('urgent');
+    expect(entry.recipient).toBe('user-1');
+    expect(entry.subject).toBe('Test notification');
+    expect(entry.timestamp).toBeInstanceOf(Date);
+  });
+
+  it('should generate sequential IDs', () => {
+    service.record({ channel: 'sms', priority: 'urgent', recipient: 'u1', subject: 's1' });
+    service.record({ channel: 'email', priority: 'normal', recipient: 'u2', subject: 's2' });
+    service.record({ channel: 'webhook', priority: 'low', recipient: 'u3', subject: 's3' });
+
+    const entries = service.getEntries();
+    expect(entries[0]?.id).toBe('audit-0001');
+    expect(entries[1]?.id).toBe('audit-0002');
+    expect(entries[2]?.id).toBe('audit-0003');
+  });
+
+  it('should filter entries by recipient', () => {
+    service.record({ channel: 'sms', priority: 'urgent', recipient: 'alice', subject: 's1' });
+    service.record({ channel: 'email', priority: 'normal', recipient: 'bob', subject: 's2' });
+    service.record({ channel: 'webhook', priority: 'low', recipient: 'alice', subject: 's3' });
+
+    expect(service.getEntriesForRecipient('alice')).toHaveLength(2);
+    expect(service.getEntriesForRecipient('bob')).toHaveLength(1);
+    expect(service.getEntriesForRecipient('charlie')).toHaveLength(0);
+  });
+
+  it('should filter entries by channel', () => {
+    service.record({ channel: 'sms', priority: 'urgent', recipient: 'u1', subject: 's1' });
+    service.record({ channel: 'email', priority: 'normal', recipient: 'u2', subject: 's2' });
+    service.record({ channel: 'sms', priority: 'urgent', recipient: 'u3', subject: 's3' });
+
+    expect(service.getEntriesByChannel('sms')).toHaveLength(2);
+    expect(service.getEntriesByChannel('email')).toHaveLength(1);
+    expect(service.getEntriesByChannel('webhook')).toHaveLength(0);
+  });
+
+  it('should count entries', () => {
+    expect(service.getEntryCount()).toBe(0);
+    service.record({ channel: 'sms', priority: 'urgent', recipient: 'u1', subject: 's1' });
+    expect(service.getEntryCount()).toBe(1);
+  });
+
+  it('should clear entries', () => {
+    service.record({ channel: 'sms', priority: 'urgent', recipient: 'u1', subject: 's1' });
+    service.clear();
+    expect(service.getEntryCount()).toBe(0);
+  });
+});

