+import { describe, it, expect, beforeEach } from 'vitest';
+import { NotificationPreferencesService } from '../../src/services/notification-preferences.service.js';
+
+describe('NotificationPreferencesService', () => {
+  let service: NotificationPreferencesService;
+
+  beforeEach(() => {
+    service = new NotificationPreferencesService();
+  });
+
+  it('should set and get a preference', () => {
+    service.setPreference('user-1', 'sms');
+    expect(service.getPreference('user-1')).toBe('sms');
+  });
+
+  it('should return undefined for unknown user', () => {
+    expect(service.getPreference('unknown')).toBeUndefined();
+  });
+
+  it('should override existing preference', () => {
+    service.setPreference('user-1', 'sms');
+    service.setPreference('user-1', 'email');
+    expect(service.getPreference('user-1')).toBe('email');
+  });
+
+  it('should remove a preference', () => {
+    service.setPreference('user-1', 'sms');
+    expect(service.removePreference('user-1')).toBe(true);
+    expect(service.getPreference('user-1')).toBeUndefined();
+  });
+
+  it('should return false when removing non-existent preference', () => {
+    expect(service.removePreference('unknown')).toBe(false);
+  });
+
+  it('should check if preference exists', () => {
+    service.setPreference('user-1', 'webhook');
+    expect(service.hasPreference('user-1')).toBe(true);
+    expect(service.hasPreference('user-2')).toBe(false);
+  });
+
+  it('should return all preferences', () => {
+    service.setPreference('user-1', 'sms');
+    service.setPreference('user-2', 'email');
+
+    const all = service.getAllPreferences();
+    expect(all.size).toBe(2);
+    expect(all.get('user-1')).toBe('sms');
+    expect(all.get('user-2')).toBe('email');
+  });
+
+  it('should clear all preferences', () => {
+    service.setPreference('user-1', 'sms');
+    service.setPreference('user-2', 'email');
+    service.clear();
+
+    expect(service.hasPreference('user-1')).toBe(false);
+    expect(service.getAllPreferences().size).toBe(0);
+  });
+});
